// ===========================================================================
// Renderer
// ===========================================================================

function addShapeFromData(pres, slide, sh) {
  if (!sh.xfrm) return;
  const { x, y, w, h } = sh.xfrm;
  const prst = sh.prst || "rect";
  const hasText = !!(sh.paras && sh.paras.length);
  const hasFill = sh.fill && sh.fill !== "none";
  const hasSolidLine = sh.line && sh.line.color && !sh.line.none;

  // Line geometry (drawn stroke, no text).
  if (prst === "line") {
    const lw   = (sh.line && sh.line.w_pt) || 1;
    const lcol = (sh.line && sh.line.color) || "000000";
    slide.addShape(pres.shapes.LINE, { x, y, w, h, line: { color: lcol, width: lw } });
    return;
  }

  // Filled rectangle (with or without overlay text).
  if (hasFill || (hasSolidLine && !hasText)) {
    const opts = { x, y, w, h };
    if (hasFill) opts.fill = { color: sh.fill };
    if (hasSolidLine) opts.line = { color: sh.line.color, width: sh.line.w_pt || 0.75 };
    else opts.line = { type: "none" };
    slide.addShape(pres.shapes.RECTANGLE, opts);
    if (!hasText) return;
  }

  // Text box.
  if (hasText) {
    const textArr = [];
    for (let pi = 0; pi < sh.paras.length; pi++) {
      const para = sh.paras[pi];
      const runs = para.runs || [];
      for (let ri = 0; ri < runs.length; ri++) {
        const run = runs[ri];
        const opts = {};
        if (run.sz)       opts.fontSize = parseInt(run.sz, 10) / 100;
        if (run.b === "1") opts.bold   = true;
        if (run.i === "1") opts.italic = true;
        if (run.color)    opts.color    = run.color;
        if (run.font)     opts.fontFace = run.font;
        if (run.spc)      opts.charSpacing = parseInt(run.spc, 10) / 100;
        if (para.algn) {
          opts.align = para.algn === "r" ? "right" : para.algn === "ctr" ? "center" : "left";
        }
        const isLastRun  = ri === runs.length - 1;
        const isLastPara = pi === sh.paras.length - 1;
        if (isLastRun && !isLastPara) opts.breakLine = true;
        textArr.push({ text: run.text || "", options: opts });
      }
      if (runs.length === 0 && pi < sh.paras.length - 1) {
        textArr.push({ text: "", options: { breakLine: true } });
      }
    }
    const boxOpts = { x, y, w, h, margin: 0, valign: "top", isTextBox: true };
    if (sh.bodyPr && sh.bodyPr.anchor) {
      if (sh.bodyPr.anchor === "ctr") boxOpts.valign = "middle";
      else if (sh.bodyPr.anchor === "b") boxOpts.valign = "bottom";
    }
    slide.addText(textArr, boxOpts);
  }
}

function addPicFromData(pres, slide, sh, slideNum) {
  if (!sh.xfrm) return;
  const { x, y, w, h } = sh.xfrm;
  // Slide 15 arrow pictures — pick up/down based on rId.
  if (slideNum === 15 && sh.rId && SLIDE15_ARROWS[sh.rId]) {
    const data = SLIDE15_ARROWS[sh.rId] === "up" ? ARROW_UP : ARROW_DOWN;
    slide.addImage({ data, x, y, w, h });
  }
}

function renderChart(pres, slide, gf, chartNum) {
  const { x, y, w, h } = gf.xfrm;
  const c = CHARTS[chartNum];
  if (!c) return;

  if (c.type === "line") {
    const data = c.series.map(s => ({
      name: s.name, labels: c.labels, values: s.values,
    }));
    const chartColors = c.series.map(s => s.color);
    const opts = {
      x, y, w, h,
      chartColors,
      lineDataSymbol: "none",
      lineSize: 2,
      showLegend: false,
      showTitle: false,
      catAxisLabelColor: "8A94A8",
      catAxisLabelFontFace: "Calibri",
      catAxisLabelFontSize: 10,
      valAxisLabelColor: "8A94A8",
      valAxisLabelFontFace: "Calibri",
      valAxisLabelFontSize: 10,
      valGridLine: { color: "E8EAEE", style: "solid", size: 0.5 },
      catGridLine: { style: "none" },
      valAxisLineShow: false,
      catAxisLineShow: false,
      valAxisLabelFormatCode: c.yValFmt || "0",
      chartArea: { fill: { color: "FAFAF7" }, border: { pt: 0, color: "FAFAF7" } },
      plotArea:  { fill: { color: "FAFAF7" } },
    };
    if (c.axis) {
      opts.valAxisMinVal   = c.axis.min;
      opts.valAxisMaxVal   = c.axis.max;
      opts.valAxisMajorUnit = c.axis.step;
    }
    slide.addChart(pres.charts.LINE, data, opts);
  } else if (c.type === "doughnut") {
    const data = [{ name: "Allocation", labels: c.labels, values: c.values }];
    slide.addChart(pres.charts.DOUGHNUT, data, {
      x, y, w, h,
      chartColors: c.colors,
      showLegend: false,
      showTitle: false,
      showValue: true,
      dataLabelColor: "FFFFFF",
      dataLabelFontFace: "Calibri",
      dataLabelFontSize: 10,
      dataLabelFontBold: true,
      dataLabelFormatCode: '0"%"',
      holeSize: c.holeSize,
      firstSliceAng: 0,
      chartArea: { fill: { color: "FAFAF7" }, border: { pt: 0, color: "FAFAF7" } },
      plotArea:  { fill: { color: "FAFAF7" } },
    });
  }
}

function buildDeck() {
  const pres = new pptxgen();
  pres.layout = "LAYOUT_WIDE"; // 13.333" x 7.5"
  pres.title  = "DoubleLine 2026 Fixed Income Outlook";
  pres.author = "DoubleLine Capital";

  for (const s of SLIDES) {
    const slide = pres.addSlide();
    if (s.bg) slide.background = { color: s.bg };

    for (const sh of s.shapes) {
      if (sh.kind === "sp") {
        addShapeFromData(pres, slide, sh);
      } else if (sh.kind === "pic") {
        addPicFromData(pres, slide, sh, s.slide_num);
      } else if (sh.kind === "graphicFrame") {
        const n = SLIDE_CHART_MAP[s.slide_num];
        if (n) renderChart(pres, slide, sh, n);
      }
    }
  }
  return pres;
}

buildDeck().writeFile({ fileName: "DoubleLine_2026_Outlook_Revised.pptx" }).then(f => {
  console.log("Wrote: " + f);
});
